  3→export const likeService = async(journalId, receiverId, senderId) =>{
  4→    if(!journalId || !receiverId){
  5→        console.error('journalId or receiverId is undefined');
  6→        throw {status: 400, error: 'journalId or receiverId is undefined'};
  7→    }
  8→
  9→    if(!senderId){
 10→        console.error('senderId is undefined');
 11→        throw {status: 400, error: 'senderId is undefined'}
 12→    }
 13→
 14→    const isOwnContent = senderId === receiverId;
 15→
 16→    const {data: existingLike, error: errorExistingLike} = await supabase
 17→    .from('likes')
 18→    .select('user_id')
 19→    .eq('user_id', senderId)
 20→    .eq('journal_id', journalId)
 21→    .maybeSingle()
 22→
 23→    if(errorExistingLike){
 24→        console.error('supabase error while checking existing like')
 25→    }
 26→
 27→    if(!existingLike){
 28→        const inserNotifPromise = supabase
 29→        .from('notifications')
 30→        .insert({
 31→            sender_id: senderId,
 32→            receiver_id: receiverId,
 33→            journal_id: journalId,
 34→            type: 'like',
 35→            read: false
 36→        })
 37→
 38→        const inserLikePromise = supabase
 39→        .from('likes')
 40→        .insert({
 41→            user_id: senderId, 
 42→            journal_id: journalId,
 43→        })
 44→
 45→        const [insertNotif, insertLike ] = await Promise.all([
 46→            isOwnContent ? Promise.resolve({error: null}) : inserNotifPromise,
 47→            inserLikePromise
 48→        ])
 49→
 50→        const {data: insertNotifcationResult, error: errorInsertNotificationResult} = insertNotif;
 51→
 52→        const {data: insertLikeResult, error: errorInserLikeResult} = insertLike;
 53→
 54→        if(errorInsertNotificationResult || errorInserLikeResult){
 55→            console.error('supabase error:', errorInserLikeResult.message || errorInsertNotificationResult.message);
 56→            throw {status: 500, error: 'supabase error while inserting likes'}
 57→        }
 58→
 59→        return {message: 'liked'};
 60→    } else {
 61→        const deleteNotifPromise = supabase
 62→        .from('notifications')
 63→        .delete()
 64→        .eq('receiver_id', receiverId)
 65→        .eq('sender_id', senderId)
 66→        .eq('journal_id', journalId)
 67→        .eq('type', 'like')
 68→
 69→        const deleteLikePromise = await supabase
 70→        .from('likes')
 71→        .delete()
 72→        .eq('user_id', senderId)
 73→        .eq('journal_id', journalId)
 74→
 75→        const [deleteNotif, deleteLike] = await Promise.all([deleteNotifPromise, deleteLikePromise]);
 76→        const {error: errorDeleteNotif} = deleteNotif;
 77→        const {error: errorDeleteLike} = deleteLike;
 78→
 79→        if(errorDeleteNotif || errorDeleteLike){
 80→            console.error('supabase error while deleting like', errorDeleteLike.message || errorDeleteNotif.message);
 81→            throw {status: 500, error: 'supabase error while deleting like'}
 82→        }
 83→
 84→        return {message: 'unliked'};
 85→    }
 86→
 87→}
